import { useEffect, useState } from "react";
import axios from "axios";
import { Link } from "react-router-dom";

export default function AfficherProjects() {
  const [projects, setProjects] = useState([]);
  const [search, setSearch] = useState("");
  const [result, setResult] = useState([]);
  const token = localStorage.getItem("token");
        let r = null;
          if(token){
              const decoded = jwtDecode(token);
              r = decoded.role; 
          }

 const getProjects = async () => {
  try {
    const res = await axios.get("http://localhost:3004/projects", {
      headers: { Authorization: `Bearer ${token}` }
    });
    setProjects(res.data);
  } catch (err) {
    console.log("ERROR:", err.response || err.message);
  }
};

  useEffect(() => {
    getProjects();
  }, []);

  const data = result.length > 0 ? result : projects;

  return (
    <>
      <Link to="/ajouter">Ajouter Projet</Link>

      <br /><br />

      <input
        type="text"
        placeholder="Search by nom"
        value={search}
        onChange={(e) => setSearch(e.target.value)}
      />
      <button onClick={async () => {
        if (!search) {
          setResult([]);
          return;
        }
        const res = await axios.get(`http://localhost:3004/searchNom/${search}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setResult(res.data);
      }}>
        search
      </button>
      <center>
        <table border="1">
        <tr>
          <th>nom</th>
          <th>description</th>
          <th>statut</th>
          <th>actions</th>
        </tr>

        {data.map((p, i) => (
          <tr key={i}>
            <td>{p.nom}</td>
            <td>{p.description}</td>
            <td>{p.statut}</td>

            <td>
              <Link to={`/modifier/${p._id}`}>modifier</Link>
              <button onClick={async () => {
                await axios.delete(`http://localhost:3004/delete/${p._id}`, {
                  headers: { Authorization: `Bearer ${token}` }
                });
                getProjects();
              }}>
                supprimer
              </button>
            </td>
          </tr>
        ))}
      </table>
      </center>
    </>

  );
}
